class Solution:
    def lastStoneWeightII(self, stones):
        total = sum(stones)
        reach = 1
        for w in stones:
            reach |= reach << w
        best = 0
        half = total // 2
        for s in range(half, -1, -1):
            if (reach >> s) & 1:
                best = s
                break
        return total - 2 * best

solutions.javascript:
var lastStoneWeightII = function(stones) {
    const total = stones.reduce((a, b) => a + b, 0);
    const dp = new Array(total + 1).fill(false);
    dp[0] = true;
    for (const w of stones) {
        for (let s = total; s >= w; s--) {
            if (dp[s - w]) dp[s] = true;
        }
    }
    let best = 0;
    const half = Math.floor(total / 2);
    for (let s = half; s >= 0; s--) {
        if (dp[s]) { best = s; break; }
    }
    return total - 2 * best;
};
